使用libpq_ce操作内存解密逃生通道 使用libpq_ce操作内存解密逃生通道 libpq_ce.so为密态特性动态库，包含libpq.so的所有内容和密态客户端解析、加密的相关功能。使用libpq_ce操作内存解密逃生通道，需要设置连接参数enable_ce=3。 #include "libpq-fe.h"
int main()
{
    char *conninfo = "dbname=postgres port=8000 host='localhost' application_name=test user='testuser' password=****** enable_ce=3";
    PGconn *conn = PQconnectdb(conninfo);
    if (PQstatus(conn) != CONNECTION_OK) {
        printf("conn err\n");
        return 0;
    }
    send_clear_token(conn);
    return 0;
} 传输和销毁密钥示例 创建好客户端加密主密钥（CMK）和数据加密密钥（CEK）后，可以通过PQenableTrustedDomain()传输和销毁密钥： void send_clear_token(PGconn *conn)
{      
    // 传输密钥，将该用户有权限使用的密钥传输到服务端
    if (PQenableTrustedDomain(conn, true)) {
        printf("send ok\n");
    } else {
        printf("%s\n", PQerrorMessage(conn));
        printf("send failed\n");
    }
    // 销毁密钥，清零传输到服务端的密钥
    if (PQenableTrustedDomain(conn, false)) {
        printf("clear ok\n");
    } else {
        printf("%s\n", PQerrorMessage(conn));
        printf("clear failed\n");
    }
    PQfinish(conn);
    return;
}

使用Go驱动操作内存解密逃生通道 使用Go驱动操作内存解密逃生通道 使用Go驱动操作内存解密逃生通道全密态数据库需要完成配置Go驱动和密钥配置等相关操作，详细请参见 使用Go驱动操作密态数据库 。 全密态数据库开启内存解密逃生通道，Go驱动连接串需要配置enable_ ce=3参数。 // 以单ip:port为例，本示例以用户名和密码保存在环境变量中为例，运行本示例前请先在本地环境中设置环境变量(环境变量名称请根据自身情况进行设置)
func main() {
    hostip := os.Getenv("GOHOSTIP")   //GOHOSTIP为写入环境变量的IP地址
    port := os.Getenv("GOPORT")       //GOPORT为写入环境变量的port
    usrname := os.Getenv("GOUSRNAME") //GOUSRNAME为写入环境变量的用户名
    passwd := os.Getenv("GOPASSWD")   //GOPASSWDW为写入环境变量的用户密码
    str := "host=" + hostip + " port=" + port + " user=" + usrname + " password=" + passwd + " dbname=postgres enable_ce=3" // DSN连接串
    // str := "opengauss://" + usrname + ":" + passwd + "@" + hostip + ":" + port + "/postgres?enable_ce=3"  // URL连接串

    // 获取数据库连接池句柄
    db, err := sql.Open("opengauss", str)
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    // Open函数仅是验证参数，Ping方法可检查数据源是否合法
    err = db.Ping()
    if err == nil {
        fmt.Printf("Connection succeed!\n")
    } else {
        log.Fatal(err)
    }
} 设置完成后，可以进行 执行密态等值查询相关的创建密钥语句 、 执行密态等值查询加密表相关的语句 、 执行加密表的预编译SQL语句 、 执行加密表的Copy In操作 。 传输和销毁密钥示例 hostip := os.Getenv("GOHOSTIP")   //GOHOSTIP为写入环境变量的IP地址
port := os.Getenv("GOPORT")       //GOPORT为写入环境变量的port
usrname := os.Getenv("GOUSRNAME") //GOUSRNAME为写入环境变量的用户名
passwd := os.Getenv("GOPASSWD")   //GOPASSWDW为写入环境变量的用户密码
// 配置自动传输密钥模式；此模式设置为yes，则将在连接初始化时自动将当前用户有权访问的所有列加密密钥发送给服务端，并在连接关闭时自动销毁
str := "host=" + hostip + " port=" + port + " user=" + usrname + " password=" + passwd + " dbname=postgres enable_ce=3 auto_sendtoken=yes"
db, err := sql.Open("opengauss", str)
if err != nil {
   log.Fatal(err)
}
defer db.Close()

// 手动执行传输与销毁密钥命令
_, err = db.Exec("send_token")
if err != nil {
    log.Fatal(err)
}
_, err = db.Exec("clear_token")
if err != nil {
    log.Fatal(err)
}

使用JDBC驱动操作内存解密逃生通道 使用JDBC驱动操作内存解密逃生通道 服务端和客户端仅在 GaussDB 503.1.0.SPC1200版本及以后版本支持JDBC操作内存解密逃生通道。 使用JDBC驱动操作内存解密逃生通道全密态数据库需要完成配置JDBC驱动和密钥配置等相关操作，详细请参见 使用JDBC操作密态数据库 。 全密态数据库开启内存解密逃生通道，JDBC连接需要设置enable_ ce=3参数。 public static Connection getConnect(String username, String passwd)
    {
        //驱动类。
        String driver = "org.postgresql.Driver";
        //数据库连接描述符。
        String sourceURL = "jdbc:postgresql://127.0.0.1: 8000 /postgres?enable_ce=3";
        Connection conn = null;

        try
        {
            //加载驱动。
            Class.forName(driver);
        }
        catch( Exception e )
        {
            e.printStackTrace();
            return null;
        }

        try
        {
             //创建连接。
            conn = DriverManager.getConnection(sourceURL, username, passwd);
            System.out.println("Connection succeed!");
        }
        catch(Exception e)
        {
            e.printStackTrace();
            return null;
        }

        return conn;
    }; 设置完成后，可以进行 调用isValid方法刷新缓存 、 执行密态等值密文解密 、 执行加密表的预编译SQL语句 、 执行加密表的批处理操作 。 传输和销毁密钥示例 // 创建客户端连接
Connection conn1 = DriverManager.getConnection("url","user","password");

// conn1通过调用setClientInfo传输密钥
try {
 conn1.setClientInfo("send_token", null);
} catch (SQLException e) {
 System.out.println("Failed to cache token in Trusted Domain.\n");
}

// conn1通过调用setClientInfo销毁密钥
try {
 conn1.setClientInfo("clear_token", null);
} catch (SQLException e) {
 System.out.println("Failed to clear token in Trusted Domain.\n");
}
